sql:
SELECT MAX(percent_at_least_partially_vaccinated) AS max_percent_partially_vaccinated
FROM vaccination_stats
WHERE vaccination_date = (SELECT MAX(vaccination_date) FROM vaccination_stats);

SELECT COUNT(*) AS outcome_count
FROM vaccination_outcomes
WHERE dhb_id = 1;

SELECT number_of_cases
   FROM vaccination_outcomes
   WHERE outcome_type = 'Hospitalization';

SELECT outcome_type, SUM(number_of_cases) AS total_cases
FROM vaccination_outcomes
GROUP BY outcome_type;

SELECT dhb_name, dhb_code
FROM dhbs
ORDER BY established_date ASC;

external_knowledge:
- "beginning of 2023" refers to January 1, 2023, or later; 
- "details" include DHB name, DHB code, region name, outcome type, number of cases, vaccination type name, manufacturer, and date; 
- "top 3 vaccination outcomes" are ranked by the number of cases in descending order for each DHB.
